/**********************************************************************************************************************
** Script to monitor table counts. Good for when tuning batch looping DELETES, INSERTS, UPDATES scripts.
** Edit the @SchemaTableName for the schema and table you wish to monitor.
** View the results in the 'Messages' tab here is SSMS.
**********************************************************************************************************************/
DECLARE @SchemaTableName nvarchar(128) = N'$SchemaName$.$TableName$';
DECLARE @UseEstimatedCount bit = 1; /* Estimate is faster. 0 = will use the actual table count. */

/* Do not edit these variables below. */
DECLARE @StartTime datetime = GETDATE();
DECLARE @LastMinuteStart datetime = DATEADD(MINUTE, -1, @StartTime);
DECLARE @CurrentMinuteStart datetime;
DECLARE @CurrentMinuteStartMessage nvarchar(30);
DECLARE @LastRowCount bigint = -1;
DECLARE @stmt nvarchar(MAX);

SET NOCOUNT ON;

WHILE 1 = 1
    BEGIN
        SET @CurrentMinuteStart = DATEADD(MINUTE, DATEDIFF(MINUTE, @StartTime, GETDATE()), @StartTime);

        DECLARE @CurrentRowCount bigint;

        IF @UseEstimatedCount = 1
            BEGIN
                SELECT
                    @CurrentRowCount = SUM(row_count)
                FROM
                    sys.dm_db_partition_stats
                WHERE
                    object_id = OBJECT_ID(@SchemaTableName)
                AND (index_id = 0 OR index_id = 1);
            END;
        ELSE
            BEGIN
                SET @stmt = N'SELECT @CurrentRowCount = COUNT_BIG(*) FROM ' + @SchemaTableName + N' WITH (READPAST);';
                EXECUTE sys.sp_executesql
                    @stmt
                   ,N'@CurrentRowCount bigint OUTPUT'
                   ,@CurrentRowCount = @CurrentRowCount OUTPUT;
            END;

        IF @LastRowCount = -1
            BEGIN
                SET @LastRowCount = @CurrentRowCount;
            END;

        DECLARE @RowCountDifference nvarchar(30) = FORMAT(ABS(@LastRowCount - @CurrentRowCount), '#,##0');

        SELECT @CurrentMinuteStartMessage = CONVERT(varchar(30), @CurrentMinuteStart, 109);

        RAISERROR('%s row difference for date %s', 0, 1, @RowCountDifference, @CurrentMinuteStartMessage) WITH NOWAIT;

        SET @LastMinuteStart = @CurrentMinuteStart;
        SET @LastRowCount = @CurrentRowCount;

        WAITFOR DELAY '00:01:00';
    END;
